import{_ as t,o as a,c as i,a0 as l}from"./chunks/framework.CWk8AOcY.js";const c=JSON.parse('{"title":"简介","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"zh/guide/introduction.md"}'),o={name:"guide/introduction.md"};function r(n,e,d,s,u,h){return a(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h1><p>欢迎查看 Cube 安全沙箱文档。</p><p>Cube Sandbox 是一款生产级的多组件安全沙箱系统，专为 Serverless 计算和安全代码执行环境设计。它实现了基于虚拟机的容器隔离架构，主要使用了 KVM 虚拟化技术。</p><h2 id="有哪些优势" tabindex="-1">有哪些优势？ <a class="header-anchor" href="#有哪些优势" aria-label="Permalink to &quot;有哪些优势？&quot;">​</a></h2><ul><li><p><strong>卓越性能</strong>：针对沙箱进行了全链路的深度优化，单实例具备 100ms 内的极速交付速度，额外内存消耗小于 5MB，单机 100 并发的情况下也能确保百毫秒级的沙箱交付。</p></li><li><p><strong>安全可控</strong>：实现了硬件级别的安全隔离，并在网络层面提供完整的安全策略支持，保障多租户环境下沙箱实例之间的安全边界。</p></li><li><p><strong>开箱即用</strong>：没有复杂的环境依赖，通过极简的部署脚本可在几分钟内在本地快速拉起一个 Cube Sandbox 环境，立即体验其核心能力，真正做到开箱即用。</p></li><li><p><strong>社区兼容</strong>：兼容 E2B 沙箱协议，现有 Agent 应用与工作流无需重构业务逻辑，就可获得安全性的显著提升。</p></li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./quickstart.html">快速开始</a> — 用最短路径从零到运行沙箱。</li><li><a href="./pvm-deploy.html">PVM 部署</a> — 在云服务器无 <code>/dev/kvm</code> 时，使用 PVM 宿主机内核 + PVM guest 内核部署 Cube Sandbox。</li><li><a href="./self-build-deploy.html">本地构建部署</a> — 单机部署参考，包含前置条件、配置说明和故障排查。</li><li><a href="./multi-node-deploy.html">多机集群部署</a> — 添加计算节点，扩展到多机集群。</li><li><a href="./tutorials/template-from-image.html">从 OCI 镜像制作模板</a> — 使用 CLI 创建、监控和管理模板的分步指南。</li></ul>',7)])])}const m=t(o,[["render",r]]);export{c as __pageData,m as default};
